using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. Strongly-typed metadata via GetTypeInfo<T>() ---

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver(),
    PropertyNamingPolicy = JsonNamingPolicy.CamelCase
};

// Generic overload returns JsonTypeInfo<T> directly — no cast needed.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Type:       {personInfo.Type.Name}");
Console.WriteLine($"Kind:       {personInfo.Kind}");
Console.WriteLine($"Properties: {string.Join(", ", personInfo.Properties.Select(p => p.Name))}");

// Round-trip via the typed metadata
Person p = new("Alice", 30);
string json = JsonSerializer.Serialize(p, personInfo);
Person p2 = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"Serialized: {json}");
Console.WriteLine($"Round-trip: {p2}");

// --- 2. Probe without throwing via TryGetTypeInfo() ---

Console.WriteLine();
ProbeType<Person>(options);   // should succeed
ProbeType<Stream>(options);   // likely has no metadata in a minimal resolver

static void ProbeType<T>(JsonSerializerOptions opts)
{
    if (opts.TryGetTypeInfo(typeof(T), out JsonTypeInfo? info))
    {
        Console.WriteLine($"[probe] {typeof(T).Name}: metadata available (Kind={info!.Kind})");
    }
    else
    {
        Console.WriteLine($"[probe] {typeof(T).Name}: no metadata available — no exception thrown");
    }
}

// --- Types ---

public record Person(string Name, int Age);

